/**
 * clampNumber
 *
 * Purpose:
 *   Small utility that clamps a numeric value between optional min and max bounds.
 *
 * API (TypeScript):
 *   clampNumber(value: number, min?: number, max?: number): number
 *
 * Parameters:
 *   - value: number
 *       The numeric value to clamp. Must be a finite number.
 *   - min?: number
 *       Optional lower bound. If provided, must be a finite number.
 *   - max?: number
 *       Optional upper bound. If provided, must be a finite number.
 *
 * Returns:
 *   - number: the clamped value. If neither min nor max are provided, returns value unchanged
 *
 * Behavior and edge cases:
 *   - If value is not a finite number (NaN, Infinity, -Infinity), a TypeError is thrown.
 *   - If min or max are provided but are not finite numbers, a TypeError is thrown.
 *   - If both min and max are provided and min > max, a RangeError is thrown.
 *   - If only min is provided, result = Math.max(value, min).
 *   - If only max is provided, result = Math.min(value, max).
 *   - If both are provided (and min <= max), result is clamped into [min, max].
 *
 * Target runtime:
 *   - Node.js 14+ (also works in modern browsers when compiled/transpiled)
 *
 * Example usage:
 *   import { clampNumber } from './index';
 *   const a = clampNumber(5, 1, 10); // 5
 *   const b = clampNumber(15, 1, 10); // 10
 *   const c = clampNumber(2, 3); // 3
 *
 */

export function clampNumber(value: number, min?: number, max?: number): number {
  if (!Number.isFinite(value)) {
    throw new TypeError('value must be a finite number');
  }
  if (min !== undefined && !Number.isFinite(min)) {
    throw new TypeError('min must be a finite number when provided');
  }
  if (max !== undefined && !Number.isFinite(max)) {
    throw new TypeError('max must be a finite number when provided');
  }
  if (min !== undefined && max !== undefined && min > max) {
    throw new RangeError('min must be <= max');
  }

  let result = value;
  if (min !== undefined) result = Math.max(result, min);
  if (max !== undefined) result = Math.min(result, max);
  return result;
}


--- tests/index.test.ts ---
import { clampNumber } from '../src/index';

describe('clampNumber', () => {
  test('returns value when inside bounds', () => {
    expect(clampNumber(5, 1, 10)).toBe(5);
  });

  test('clamps value above max to max', () => {
    expect(clampNumber(15, 1, 10)).toBe(10);
  });

  test('clamps value below min to min', () => {
    expect(clampNumber(-5, 0, 10)).toBe(0);
  });

  test('min only clamps lower bound', () => {
    expect(clampNumber(2, 3)).toBe(3);
    expect(clampNumber(5, 3)).toBe(5);
  });

  test('max only clamps upper bound', () => {
    expect(clampNumber(8, undefined, 6)).toBe(6);
    expect(clampNumber(4, undefined, 6)).toBe(4);
  });

  test('throws when min > max', () => {
    expect(() => clampNumber(5, 10, 1)).toThrow(RangeError);
  });

  test('throws on non-finite value', () => {
    expect(() => clampNumber(NaN, 1, 2)).toThrow(TypeError);
    expect(() => clampNumber(Infinity)).toThrow(TypeError);
  });

  test('throws on non-finite min/max when provided', () => {
    expect(() => clampNumber(1, NaN)).toThrow(TypeError);
    expect(() => clampNumber(1, undefined, Infinity)).toThrow(TypeError);
  });
});


